static inline at::Tensor conv2d_valid_output_like(const at::Tensor& x, const at::Tensor& w) {
    // x: [N, C, H, W], w: [Co, C, Kh, Kw]
    auto sizes = x.sizes();
    int64_t N = sizes[0];
    int64_t C = sizes[1];
    int64_t H = sizes[2];
    int64_t W = sizes[3];
    int64_t Co = w.size(0);
    int64_t Ci = w.size(1);
    int64_t Kh = w.size(2);
    int64_t Kw = w.size(3);
    TORCH_CHECK(C == Ci, "Input and weight channel mismatch");
    int64_t Hout = H - Kh + 1;
    int64_t Wout = W - Kw + 1;
    TORCH_CHECK(Hout > 0 && Wout > 0, "Invalid output size for given kernel");
    return at::empty({N, Co, Hout, Wout}, x.options());
}

at::Tensor conv_standard_2d_asymmetric_input_asymmetric_kernel_custom_impl_npu(const at::Tensor& x, const at::Tensor& weight) {
